fn match_example(value: Int) -> String {
    match value {
        1 -> "One",
        2 -> "Two",
        _ -> "Other"
    }
}

type Result = Ok(Int) | Error(String);

fn process(value: Int) -> Result {
    if value > 0 {
        Ok(value)
    } else {
        Error("Negative value")
    }
}

fn spawn_example() {
    spawn fn do_work() {
        // Simulate some work
        delay(1000);
    }
}

fn divide(a: Int, b: Int) -> Result {
    if b == 0 {
        Error("Division by zero")
    } else {
        Ok(a / b)
    }
}

module Math {
    pub fn add(a: Int, b: Int) -> Int {
        a + b
    }
}
